// Time: O(n) | Space: O(n)
public int[] twoSum(int[] nums, int target) {
    Map<Integer, Integer> seen = new HashMap<>();
    for (int i = 0; i < nums.length; i++) {
        int comp = target - nums[i];
        if (seen.containsKey(comp))
            return new int[]{seen.get(comp), i};
        seen.put(nums[i], i);
    }
    return new int[]{};
}

