    int left = 0, ans = 0;
    for (int right = 0; right < s.size(); right++) {
        while (seen.count(s[right]))
            seen.erase(s[left++]);
        seen.insert(s[right]);
        ans = max(ans, right - left + 1);
    }
    return ans;
}

