# Approach: Expand around center for odd and even palindromes
# Time: O(n^2) | Space: O(1)
def longestPalindrome(s):
    res = ''
    for i in range(len(s)):
        for l, r in [(i,i), (i,i+1)]:  # odd and even centers
            while l >= 0 and r < len(s) and s[l] == s[r]:
                l -= 1; r += 1
            if r - l - 1 > len(res):
                res = s[l+1:r]
    return res

